using UnityEngine; using NabyeolDabyeolDreamPuzzle.Stage;
namespace NabyeolDabyeolDreamPuzzle.Agents { public class DifficultyGoalBinder:MonoBehaviour{ [SerializeField] GoalManager goalManager; [SerializeField] DifficultyAgent difficultyAgent; [SerializeField] bool resetFailuresOnClear=true; [SerializeField] bool logSuggestionOnFailure=true; void Awake(){ goalManager??=FindAnyObjectByType<GoalManager>(); difficultyAgent??=FindAnyObjectByType<DifficultyAgent>(); } void OnEnable(){ if(goalManager!=null){ goalManager.OnStageFailed+=Fail; goalManager.OnStageCleared+=Clear; }} void OnDisable(){ if(goalManager!=null){ goalManager.OnStageFailed-=Fail; goalManager.OnStageCleared-=Clear; }} public void LogCurrentDifficultySuggestion(){ if(difficultyAgent!=null) Debug.Log(difficultyAgent.EvaluateSuggestion().message); } void Fail(){ if(difficultyAgent==null)return; difficultyAgent.RegisterFailure(); if(logSuggestionOnFailure) LogCurrentDifficultySuggestion(); } void Clear(){ if(difficultyAgent!=null&&resetFailuresOnClear) difficultyAgent.ResetFailureCount(); }} }
